import{_ as e,o as a,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Roku","description":"","frontmatter":{"title":"Roku","slug":"roku"},"headers":[],"relativePath":"marketer-hub/roku.md","filePath":"marketer-hub/roku.md"}'),d={name:"marketer-hub/roku.md"};function n(i,t,s,u,l,h){return a(),r("div",null,[...t[0]||(t[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>For marketers utilizing Branch and Roku, this article details how to integrate Branch&#39;s robust deep linking and attribution features within your Roku ad campaigns.</p><p>Learn how this integration can improve the user journey and provide clearer insights into your advertising effectiveness on the Roku platform</p><p><strong>Roku Ad Manager</strong><br> Roku&#39;s Self-Attributing Ad Network, provides access for its third-party Measurement Partners to request attribution for install and event attribution for clients utilizing Roku’s Endemic(i.e. streaming) Media to help drive distribution and re-engagement of their apps. Similar to other Self-Attributing Networks (SANs), Roku will be able to receive conversion events tracked via Branch SDK and use it for performance optimization, audience segmenting, and re-targeting.</p><div class="info custom-block"><p class="custom-block-title">Roku Data Sharing</p><p>Roku last-attributed data will be wiped at the log-level (via <a href="./custom-exports-api.html">Custom Exports</a> and <a href="./daily-exports-api.html">Daily Exports</a>) and this data will appear as <strong>null/blank</strong> in exports but you can still export it via aggregated data (<a href="./aggregate-api.html">Aggregate API</a> or <a href="./query-api.html">Query API</a>)</p></div><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable Roku, you first need to:</p><ol><li><p>Create a <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Enable <a href="https://help.branch.io/docs/packaging#performance-pro-tier" target="_blank" rel="noreferrer">Household Measurement</a> for your Branch account. Household Measurement requires a premium plan. Please <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact our Sales team</a> to learn more about pricing and availability.</p></li><li><p><em>(Optional)</em> Implement the Branch SDK into your OTT/CTV app:</p><ul><li><a href="./roku-basic-integration.html">Roku SDK</a></li><li><a href="https://help.branch.io/developers-hub/docs/connected-sdk-index" target="_blank" rel="noreferrer">Connected SDK</a></li><li><a href="./desktop-over-the-top-ott-attribution.html">OTT Server-to-Server</a></li></ul></li><li><p>Have admin access to your <a href="https://advertising.roku.com/" target="_blank" rel="noreferrer">Roku Account</a>.</p></li></ol><h2 id="enable-roku" tabindex="-1">Enable Roku <a class="header-anchor" href="#enable-roku" aria-label="Permalink to &quot;Enable Roku&quot;">​</a></h2><p>To enable Roku, you can either use Roku Ads Manager or Roku managed services.</p><h3 id="enable-roku-with-roku-ads-manager" tabindex="-1">Enable Roku with Roku Ads Manager <a class="header-anchor" href="#enable-roku-with-roku-ads-manager" aria-label="Permalink to &quot;Enable Roku with Roku Ads Manager&quot;">​</a></h3><p>To enable Roku with Roku Ads Manager, complete the steps below:</p><ol><li><p>Sign in to <a href="https://ads.roku.com/" target="_blank" rel="noreferrer">Roku Ads Manager</a>.</p></li><li><p>Navigate to the <a href="https://ads.roku.com/pixels" target="_blank" rel="noreferrer">Events page</a>.</p></li><li><p>Identify an existing Event Group or create a new Event Group.</p></li><li><p>Copy the Event Group ID.<br><em>[Image: Roku Ads Manager interface showing event group ID and event source status.]</em>.png)</p></li><li><p>Send Roku (<a href="mailto:adsmanagersupport@roku.com" target="_blank" rel="noreferrer">adsmanagersupport@roku.com</a>) the following information:</p><ol><li>Your MMP name (Branch)</li><li>Your Event Group ID</li></ol></li></ol><h3 id="enable-roku-with-managed-services" tabindex="-1">Enable Roku with managed services <a class="header-anchor" href="#enable-roku-with-managed-services" aria-label="Permalink to &quot;Enable Roku with managed services&quot;">​</a></h3><p>To enable Roku with managed services, you will need Roku to provide you with an Event Group ID. Please reach out to your Roku representative for this.</p><h2 id="connect-roku-in-branch" tabindex="-1"><strong>Connect Roku in Branch</strong> <a class="header-anchor" href="#connect-roku-in-branch" aria-label="Permalink to &quot;**Connect Roku in Branch**&quot;">​</a></h2><p>To connect Roku in Branch, complete the steps below:</p><ol><li><p>In the Branch Dashboard, navigate to the <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer">Ads Partner page</a>, search for “RokuSAN” and select it. Do <strong>not</strong> use the “Roku” option.</p></li><li><p>Enter your Roku Ads Manager Event Group ID and click <strong>Save</strong>.</p></li><li><p>Switch to the <a href="https://dashboard.branch.io/ads/partner-management/a_ott_roku_san?tab=events" target="_blank" rel="noreferrer">Events Config tab</a> and map your Branch app events to Roku Ads Manager events.</p><ol><li>Events will appear in Roku Ads Manager attribution reporting based on this mapping configuration.</li><li>Click <strong>Save.</strong></li></ol></li><li><p>(Optional) After configuring your events, navigate to the <a href="https://dashboard.branch.io/ads/partner-management/a_roku?tab=attribution_windows" target="_blank" rel="noreferrer">Attribution Windows tab</a> to set windows by attribution type. Here are Roku’s recommended attribution window settings:</p><table tabindex="0"><thead><tr><th>Attribution Type</th><th>Window</th></tr></thead><tbody><tr><td>click to session start</td><td>1 day</td></tr><tr><td>click to install</td><td>7 days</td></tr><tr><td>click to conversion event</td><td>1 day</td></tr><tr><td>impression to session start</td><td>1 day</td></tr><tr><td>impression to install</td><td>1 day</td></tr><tr><td>impression to conversion event</td><td>1 day</td></tr></tbody></table></li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>Events can take up to 4 hours to appear in Roku Ads Manager.</p></div><h2 id="data-mapping-between-roku-branch" tabindex="-1">Data mapping between Roku &amp; Branch <a class="header-anchor" href="#data-mapping-between-roku-branch" aria-label="Permalink to &quot;Data mapping between Roku &amp; Branch&quot;">​</a></h2><p>Branch maps the following data fields from Roku to Branch:</p><table tabindex="0"><thead><tr><th>Roku Data</th><th>Branch Data</th><th>Possible Values</th></tr></thead><tbody><tr><td>Touch Type</td><td>last_attributed_touch_type</td><td>CLICK or IMPRESSION</td></tr><tr><td>Account ID</td><td>last_attributed_touch_data_tilde_advertising_account_id</td><td>The ID of your Roku Ads Manager account</td></tr><tr><td>Account Name</td><td>last_attributed_touch_data_tilde_advertising_account_name</td><td>The name of your Roku Ads Manager account</td></tr><tr><td>Campaign ID</td><td>last_attributed_touch_data_tilde_campaign_id</td><td>The ID of your Roku campaign</td></tr><tr><td>Campaign Name</td><td>last_attributed_touch_data_tilde_campaign</td><td>The name of your Roku campaign</td></tr><tr><td>Creative ID</td><td>last_attributed_touch_data_tilde_creative_id</td><td>The ID of your Roku creative</td></tr><tr><td>Creative Name</td><td>last_attributed_touch_data_tilde_creative_name</td><td>The name of your Roku creative</td></tr><tr><td>Flight ID</td><td>last_attributed_touch_data_tilde_ad_set_id</td><td>The ID of the Roku line item</td></tr><tr><td>Flight Name</td><td>last_attributed_touch_data_tilde_ad_set_name</td><td>The name of the Roku line item</td></tr><tr><td>Content ID</td><td>last_attributed_touch_data_tilde_content_id</td><td>The ID of the Roku content</td></tr><tr><td>Placement Type</td><td>last_attributed_touch_data_tilde_placement</td><td><code>mychannels</code> or <code>screensaver</code></td></tr><tr><td>Timestamp</td><td>last_attributed_touch_timestamp</td><td>Timestamp of the ad impression or click</td></tr></tbody></table><h2 id="forwarding-events-to-roku" tabindex="-1">Forwarding events to Roku <a class="header-anchor" href="#forwarding-events-to-roku" aria-label="Permalink to &quot;Forwarding events to Roku&quot;">​</a></h2><p>Once you begin tracking events through the Branch SDK, we will start sending them to Roku. Roku has pre-defined events that map to pre-defined Branch events, listed below.</p><p>Branch will forward in-app events to Roku for campaign optimization. In addition, Branch will receive attribution data for rich analysis in the Branch Dashboard.</p><table tabindex="0"><thead><tr><th>Branch Event Name</th><th>Roku Event Name</th><th>Roku Description</th></tr></thead><tbody><tr><td>INSTALL</td><td>APP_INSTALL</td><td>When a user installs an app, or the first time an app is opened/launched.</td></tr><tr><td>REINSTALL</td><td>APP_INSTALL</td><td>When a user installs an app, or the first time an app is opened/launched.</td></tr><tr><td>OPEN</td><td>SESSION_START</td><td>When a user starts an app session.</td></tr><tr><td>START_TRIAL</td><td>START_TRIAL</td><td>When a user starts a free trial of a product or service you offer.</td></tr><tr><td>COMPLETE_REGISTRATION</td><td>COMPLETE_REGISTRATION</td><td>When a user completes a registration form.</td></tr><tr><td>SUBSCRIBE</td><td>SUBSCRIBE</td><td>When a user applies to a start a paid subscription for a product or service you offer.</td></tr><tr><td>COMPLETE_STREAM</td><td>QSS</td><td>Trigger Quality Streaming Session on Video Views exceeding 5M of contiguous video play back time.</td></tr><tr><td>ADD_TO_CART</td><td>ADD_TO_CART</td><td>When a user adds a product to their shopping cart.</td></tr><tr><td>ACHIEVE_LEVEL</td><td>ACHIEVE_LEVEL</td><td>When a user reaches a certain level that you have defined in your game.</td></tr><tr><td>ADD_PAYMENT_INFO</td><td>ADD_PAYMENT_INFO</td><td>When a user adds payment information during the checkout flow.</td></tr><tr><td>ADD_TO_WISHLIST</td><td>ADD_TO_WISHLIST</td><td>When a user adds a product to their wishlist.</td></tr><tr><td>INITIATE_PURCHASE</td><td>INITIATE_CHECKOUT</td><td>When a user enters the checkout flow, prior to completing the checkout flow.</td></tr><tr><td>SEARCH</td><td>SEARCH</td><td>When a user uses your search feature.</td></tr><tr><td>LOGIN</td><td>SIGN_UP</td><td>When a user applies for a product, service, or program you offer.</td></tr><tr><td>PAGEVIEW</td><td>PAGE_VIEW</td><td>When a user visits a page; uses default pixel tracking.</td></tr><tr><td>PURCHASE</td><td>PURCHASE</td><td>When a user completes a purchase or completes the checkout flow.</td></tr><tr><td>CUSTOM_EVENT</td><td>CONTACT</td><td>When a user initiates contact with your business via telephone, SMS, email, chat, etc.</td></tr><tr><td>CUSTOM_EVENT</td><td>CUSTOMIZE_PRODUCT</td><td>When a user customizes a product.</td></tr><tr><td>CUSTOM_EVENT</td><td>DONATE</td><td>When a user donates funds to your organization or cause.</td></tr><tr><td>CUSTOM_EVENT</td><td>DOWNLOAD</td><td>When a user downloads a doc, info, or service.</td></tr><tr><td>CUSTOM_EVENT</td><td>FIND_LOCATION</td><td>When a user searches for a location of your store via a website or app, with an intention to visit the physical location.</td></tr><tr><td>CUSTOM_EVENT</td><td>FIRST_VIDEO_VIEW</td><td>When a user first views a video. This will map to Roku FTV.</td></tr><tr><td>CUSTOM_EVENT</td><td>LEAD</td><td>When a user completes a sign up.</td></tr><tr><td>CUSTOM_EVENT</td><td>SCHEDULE</td><td>When a user books an appointment to visit one of your locations.</td></tr><tr><td>CUSTOM_EVENT</td><td>SUBSCRIPTION_CANCELLATION</td><td>When a user cancels their subscription.</td></tr><tr><td>CUSTOM_EVENT</td><td>SUBSCRIPTION_RENEWAL</td><td>When a subscription is auto-renewed - this could be system generated event.</td></tr></tbody></table>',26)])])}const m=e(d,[["render",n]]);export{p as __pageData,m as default};
